  ThemeData theme(
    ColorScheme colorScheme,
    BadgeThemeData badgeThemeData, {
    required AppColors appColors,
    PillChipThemeData? pillChip,
    PillSegmentedButtonThemeData? pillSegmentedButton,
  }) => ThemeData(
    extensions: [appColors, if (pillChip != null) pillChip, if (pillSegmentedButton != null) pillSegmentedButton],
    useMaterial3: true,
    badgeTheme: badgeThemeData.copyWith(
      textStyle: TextStyle(fontWeight: FontWeight.w500, fontSize: 12, color: badgeThemeData.textColor),
    ),
    brightness: colorScheme.brightness,
    colorScheme: colorScheme,
    textTheme: textTheme
        .apply(bodyColor: colorScheme.onSurface, displayColor: colorScheme.onSurface)
        .copyWith(labelLarge: textTheme.labelLarge!.copyWith(color: colorScheme.onSurface, height: 1.6))
        .copyWith(
          titleLarge: textTheme.titleLarge!.copyWith(
            fontSize: 16,
            fontWeight: FontWeight.w500,
            color: colorScheme.onSurface,
            height: 1.8,
          ),
          titleMedium: textTheme.titleMedium!.copyWith(
            fontSize: 14,
            fontWeight: FontWeight.w500,
            color: colorScheme.onSecondaryContainer,
            height: 1.6,
          ),
        ),
    scaffoldBackgroundColor: colorScheme.surface,
    canvasColor: colorScheme.surface,
    // iOS needs CupertinoPageTransitionsBuilder to support the swipe-right-to-go-back gesture.
    // FadeForwardsPageTransitionsBuilder does not provide this gesture.
    pageTransitionsTheme: PageTransitionsTheme(
      builders: Map<TargetPlatform, PageTransitionsBuilder>.fromIterable(
        TargetPlatform.values,
        value: (platform) => platform == TargetPlatform.iOS
            ? const CupertinoPageTransitionsBuilder()
            : const FadeForwardsPageTransitionsBuilder(),
      ),
    ),
    segmentedButtonTheme: SegmentedButtonThemeData(
      style: ButtonStyle(
        backgroundColor: WidgetStateProperty.resolveWith((states) {
          if (states.contains(WidgetState.selected)) {
            return colorScheme.surfaceContainerHigh;
          }
          return colorScheme.primaryContainer;
        }),
        shape: WidgetStateProperty.all(RoundedRectangleBorder(borderRadius: BorderRadius.circular(8))),
        foregroundColor: WidgetStateProperty.all(colorScheme.onSurface),
        overlayColor: defaultTargetPlatform == TargetPlatform.iOS ? WidgetStateProperty.all(Colors.transparent) : null,
        splashFactory: defaultTargetPlatform == TargetPlatform.iOS ? NoSplash.splashFactory : null,
        textStyle: WidgetStateProperty.all(const TextStyle(fontSize: 13, fontWeight: FontWeight.w500)),
      ),
    ),
    listTileTheme: ListTileThemeData(
      titleTextStyle: TextStyle(color: colorScheme.onSurface, fontWeight: FontWeight.w500, fontSize: 16),
      subtitleTextStyle: TextStyle(color: colorScheme.onSecondaryContainer, fontWeight: FontWeight.w500, fontSize: 14),
      leadingAndTrailingTextStyle: TextStyle(
        color: colorScheme.onSecondaryContainer,
        fontWeight: FontWeight.w500,
        fontSize: 16,
      ),
    ),
  );

