class AppColors extends ThemeExtension<AppColors> {
  const AppColors({required this.primaryMuted});

  /// A muted/lighter variant of primary, for use as a subdued accent on primary surfaces
  final Color primaryMuted;

  @override
  AppColors copyWith({Color? primaryMuted}) {
    return AppColors(primaryMuted: primaryMuted ?? this.primaryMuted);
  }

  @override
  AppColors lerp(AppColors? other, double t) {
    if (other is! AppColors) return this;
    return AppColors(primaryMuted: Color.lerp(primaryMuted, other.primaryMuted, t)!);
  }
}

class ExtendedColor {
  final Color seed, value;
  final ColorFamily light;
  final ColorFamily lightHighContrast;
  final ColorFamily lightMediumContrast;
  final ColorFamily dark;
  final ColorFamily darkHighContrast;
  final ColorFamily darkMediumContrast;

  const ExtendedColor({
    required this.seed,
    required this.value,
    required this.light,
    required this.lightHighContrast,
    required this.lightMediumContrast,
    required this.dark,
    required this.darkHighContrast,
    required this.darkMediumContrast,
  });
}

class ColorFamily {
  const ColorFamily({
    required this.color,
    required this.onColor,
    required this.colorContainer,
    required this.onColorContainer,
  });

  final Color color;
  final Color onColor;
  final Color colorContainer;
  final Color onColorContainer;
}
